import React, { useEffect, useState } from "react";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "./ui/Table";
import { useNavigate } from "react-router-dom";
import { AlertDialog } from "@radix-ui/react-alert-dialog";
import { AlertDialogTrigger } from "./ui/AlertDialog";

const BookList = () => {
  const [books, setBooks] = useState([]);
  const navigate = useNavigate();
  useEffect(() => {
    fetch("http://localhost:3000/api/book")
      .then((response) => response.json())
      .then((data) => setBooks(data))
      .catch((error) => console.error("erro for the data fetching ", error));
  }, []);

  const handleClick = (id) => {
    console.log("you click" + id);
    navigate(`/bookShow/${id}`);
  };
  return (
    <AlertDialog>
      <div className="w-full h-screen flex justify-center my-5">
        <div className="container">
          <Table>
            <TableHeader className="bg-blue-300 text-white">
              <TableRow>
                <TableHead className="w-[100px]  hidden sm:flex">ID</TableHead>
                <TableHead>Title</TableHead>
                <TableHead>description</TableHead>
                <TableHead className="text-right">Nombre des page</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {books.map((book) => (
                AlertDialogTrigger
              ))}
            </TableBody>
          </Table>
        </div>
      </div>
    </AlertDialog>
  );
};

export default BookList;
